import os
from pathlib import Path

def delete_uploaded_file(user_file_id, upload_dir, file_id_mapping):
    """
    Delete a user's uploaded file from the 'uploads' directory based on file ID.
    
    Args:
        user_file_id (str): The file ID provided by the user
        upload_dir (str): The base upload directory path
        file_id_mapping (dict): Server-side mapping of file IDs to actual file paths
    
    Returns:
        bool: True if deletion was successful, False otherwise
    
    Raises:
        ValueError: If the file ID is invalid or path traversal is detected
        FileNotFoundError: If the file does not exist
    """
    # Validate input
    if not user_file_id or not upload_dir or not file_id_mapping:
        raise ValueError("Invalid input parameters")
    
    # Check if file ID exists in mapping
    if user_file_id not in file_id_mapping:
        raise ValueError("Invalid file ID")
    
    # Get the actual file path from the mapping
    relative_path = file_id_mapping[user_file_id]
    
    # Canonicalize the paths
    base_path = Path(upload_dir).resolve()
    user_path = Path(relative_path)
    
    # Construct full path
    full_path = (base_path / user_path).resolve()
    
    # Verify the full path is under the base directory
    if not full_path.is_relative_to(base_path):
        raise ValueError("Path traversal detected")
    
    # Check if the file exists
    if not full_path.exists():
        raise FileNotFoundError("File not found")
    
    # Check if the path points to a file (not directory)
    if not full_path.is_file():
        raise ValueError("Path is not a file")
    
    # Delete the file
    os.remove(full_path)
    
    # Remove the mapping entry
    del file_id_mapping[user_file_id]
    
    return True